# Databricks notebook source
# MAGIC %md
# MAGIC # Site Feasibility Stall Risk Model
# MAGIC
# MAGIC Trains per-TA GradientBoosting classifiers on the synthetic monthly enrollment
# MAGIC time series generated by `00_seed_data.py`, then:
# MAGIC
# MAGIC 1. Runs inference on each site's latest-month feature snapshot
# MAGIC 2. Computes SHAP attributions for explainability
# MAGIC 3. Refreshes `gold_model_predictions`, `gold_shap_values`,
# MAGIC    `gold_site_feasibility_scores`, and `gold_feasibility_dimension_drivers`
# MAGIC    so all four gold tables reflect genuine model output rather than hard-coded formulas.
# MAGIC
# MAGIC **Prerequisites:** `00_seed_data.py` must have been run first.

# COMMAND ----------

# MAGIC %pip install shap --quiet

# COMMAND ----------

dbutils.widgets.text("catalog", "")
CATALOG = dbutils.widgets.get("catalog")
if not CATALOG:
    raise ValueError("catalog widget is required")
print(f"Training against catalog: {CATALOG}")

# COMMAND ----------

import warnings
warnings.filterwarnings("ignore")

import numpy as np
import pandas as pd
from sklearn.ensemble import GradientBoostingClassifier, GradientBoostingRegressor
from sklearn.preprocessing import LabelEncoder
import shap

# ── Study metadata (mirrors 00_seed_data.py) ──────────────────────────────────
STUDIES = {
    "CDISCPILOT01": {"ta": "CNS",          "indication": "Alzheimer's Disease"},
    "SYNAL01":      {"ta": "CNS",          "indication": "ALS (Amyotrophic Lateral Sclerosis)"},
    "SYNAL02":      {"ta": "CNS",          "indication": "ALS (Amyotrophic Lateral Sclerosis)"},
    "SYNMS01":      {"ta": "CNS",          "indication": "Multiple Sclerosis"},
    "SYNPD01":      {"ta": "CNS",          "indication": "Parkinson's Disease"},
    "SYNPD02":      {"ta": "CNS",          "indication": "Parkinson's Disease"},
    "SYNONC01":     {"ta": "Oncology",     "indication": "Non-Small Cell Lung Cancer"},
    "SYNONC02":     {"ta": "Oncology",     "indication": "Non-Small Cell Lung Cancer"},
    "SYNONC03":     {"ta": "Oncology",     "indication": "Breast Cancer"},
    "SYNONC04":     {"ta": "Oncology",     "indication": "Colorectal Cancer"},
    "SYNONC05":     {"ta": "Oncology",     "indication": "Ovarian Cancer"},
    "SYNONC06":     {"ta": "Oncology",     "indication": "Breast Cancer"},
    "SYNRD01":      {"ta": "Rare Disease", "indication": "Gaucher Disease Type 1"},
    "SYNRD02":      {"ta": "Rare Disease", "indication": "Fabry Disease"},
    "SYNRD03":      {"ta": "Rare Disease", "indication": "Pompe Disease"},
    "SYNRD04":      {"ta": "Rare Disease", "indication": "Sickle Cell Disease"},
}

# Feature → display name mapping (matches app's SHAP panel labels)
FEATURE_DISPLAY = {
    "trailing_3m_avg_rands":    "Avg Monthly Randomizations (12m)",
    "stall_rate_ytd":           "Historical Stall Rate",
    "screen_failure_rate_ytd":  "Screen Failure Rate",
    "deviations_per_100_ytd":   "Protocol Deviation Rate",
    "months_since_activation":  "Months Since Site Activation",
    "velocity_trend_slope":     "Enrollment Velocity Ratio",
    "pct_cap_achieved":         "% Enrollment Target Achieved",
    "trailing_6m_avg_rands":    "6-Month Avg Randomizations",
    "conversion_rate_ytd":      "Screen-to-Enroll Conversion Rate",
    "n_stall_months_ytd":       "Stall Month Count",
    "ta_cnx":                   "TA: Central Nervous System",
    "ta_oncology":              "TA: Oncology",
    "ta_rare":                  "TA: Rare Disease",
}

FEATURES = list(FEATURE_DISPLAY.keys())

# COMMAND ----------
# ── Load silver tables ─────────────────────────────────────────────────────────

enroll_df = spark.table(f"{CATALOG}.ctms_data.silver_site_monthly_enrollment").toPandas()
monitor_df = spark.table(f"{CATALOG}.ctms_data.silver_site_monthly_monitoring").toPandas()
print(f"Enrollment rows: {len(enroll_df):,}  |  Monitoring rows: {len(monitor_df):,}")

# Add TA column
enroll_df["ta"] = enroll_df["study_id"].map(lambda s: STUDIES.get(s, {}).get("ta", "CNS"))

# COMMAND ----------
# ── Build rolling feature matrix ───────────────────────────────────────────────
# One row per (study_id, site_id, month_index) where month >= 3 (need ≥2 months
# of history for trailing windows). Label = next_month_is_stall.

def _rolling_features(group: pd.DataFrame, mon_group: pd.DataFrame) -> pd.DataFrame:
    """Compute time-varying features for one (study_id, site_id) sequence."""
    g      = group.sort_values("month_index").reset_index(drop=True)
    mg     = mon_group.sort_values("month_index").reset_index(drop=True) if len(mon_group) else pd.DataFrame()
    n      = len(g)
    rows   = []

    # Cumulative sums
    cum_rands   = g["rands_this_month"].cumsum().values
    cum_screens = g["screens_this_month"].cumsum().values
    cum_sf      = g["screen_failures_this_month"].cumsum().values

    # Activation month = first month with screens > 0
    active_mask = g["screens_this_month"].values > 0
    activation_idx = int(np.argmax(active_mask)) if active_mask.any() else n - 1

    planned = int(g["planned_enrollment"].iloc[0])

    for i in range(2, n):   # need at least 2 prior months
        month = int(g["month_index"].iloc[i])
        rands_now = int(g["rands_this_month"].iloc[i])

        # Skip if site not yet activated at this point
        if i < activation_idx:
            continue

        months_active = max(1, i - activation_idx + 1)

        # Trailing averages
        t3  = float(np.mean(g["rands_this_month"].iloc[max(0, i-2):i+1]))
        t6  = float(np.mean(g["rands_this_month"].iloc[max(0, i-5):i+1]))

        # Velocity trend slope (linear regression on last 3 months)
        window = g["rands_this_month"].iloc[max(0, i-2):i+1].values.astype(float)
        if len(window) >= 2:
            xs = np.arange(len(window), dtype=float)
            slope = float(np.polyfit(xs, window, 1)[0])
        else:
            slope = 0.0

        # Stall history
        past_rands       = g["rands_this_month"].iloc[activation_idx:i+1].values
        n_stalls         = int((past_rands == 0).sum())
        stall_rate       = n_stalls / max(1, len(past_rands))

        # Capacity
        pct_cap          = min(1.0, float(cum_rands[i]) / max(1, planned))

        # Screen failure / conversion
        sf_rate          = float(cum_sf[i]) / max(1, float(cum_screens[i]))
        conv_rate        = float(cum_rands[i]) / max(1, float(cum_screens[i]))

        # Deviations (from monitoring table)
        if len(mg) > 0:
            mon_slice  = mg[mg["month_index"] <= month]
            ytd_devs   = int(mon_slice["deviations_this_month"].sum())
            devs_p100  = float(ytd_devs) / max(1, float(cum_rands[i])) * 100
        else:
            devs_p100  = 0.0

        # TA dummies
        ta   = STUDIES.get(str(g["study_id"].iloc[0]), {}).get("ta", "CNS")
        ta_c = 1 if ta == "CNS"          else 0
        ta_o = 1 if ta == "Oncology"     else 0
        ta_r = 1 if ta == "Rare Disease" else 0

        # Label: is next month a stall? (defined as 0 rands, only if in range)
        if i + 1 < n:
            label = 1 if int(g["rands_this_month"].iloc[i + 1]) == 0 else 0
        else:
            label = None   # last month — no label

        rows.append({
            "study_id":              str(g["study_id"].iloc[0]),
            "site_id":               str(g["site_id"].iloc[0]),
            "month_index":           month,
            "trailing_3m_avg_rands": round(t3, 3),
            "trailing_6m_avg_rands": round(t6, 3),
            "velocity_trend_slope":  round(slope, 4),
            "months_since_activation": months_active,
            "pct_cap_achieved":      round(pct_cap, 4),
            "n_stall_months_ytd":    n_stalls,
            "stall_rate_ytd":        round(stall_rate, 4),
            "screen_failure_rate_ytd": round(sf_rate, 4),
            "conversion_rate_ytd":   round(conv_rate, 4),
            "deviations_per_100_ytd": round(devs_p100, 3),
            "ta_cnx":                ta_c,
            "ta_oncology":           ta_o,
            "ta_rare":               ta_r,
            "rands_this_month":      rands_now,
            "ta":                    ta,
            "next_month_is_stall":   label,
        })
    return pd.DataFrame(rows)


feature_dfs = []
for (study_id, site_id), grp in enroll_df.groupby(["study_id", "site_id"]):
    mon_grp = monitor_df[(monitor_df["study_id"] == study_id) & (monitor_df["site_id"] == site_id)]
    feat_df = _rolling_features(grp, mon_grp)
    if len(feat_df):
        feature_dfs.append(feat_df)

feat_all = pd.concat(feature_dfs, ignore_index=True)
print(f"Feature matrix: {len(feat_all):,} rows  |  {feat_all['next_month_is_stall'].notna().sum():,} labelled")

# COMMAND ----------
# ── Train per-TA stall classifier + enrollment regressor ──────────────────────

# Training rows: labelled, site is active (trailing_3m_avg_rands or screens > 0)
train_df = feat_all[feat_all["next_month_is_stall"].notna()].copy()
train_df["next_month_is_stall"] = train_df["next_month_is_stall"].astype(int)

TAS = ["CNS", "Oncology", "Rare Disease"]
clf_models  = {}   # stall classifier per TA
reg_models  = {}   # enrollment regressor per TA

for ta in TAS:
    subset = train_df[train_df["ta"] == ta]
    if len(subset) < 20:
        print(f"  {ta}: too few rows ({len(subset)}), skipping — will use global model")
        continue

    X = subset[FEATURES].fillna(0).values
    y_clf = subset["next_month_is_stall"].values
    y_reg = subset["rands_this_month"].values.astype(float)

    clf = GradientBoostingClassifier(
        n_estimators=120, max_depth=4, learning_rate=0.08,
        subsample=0.8, min_samples_leaf=3, random_state=42,
    )
    clf.fit(X, y_clf)
    clf_models[ta] = clf

    reg = GradientBoostingRegressor(
        n_estimators=100, max_depth=3, learning_rate=0.08,
        subsample=0.8, min_samples_leaf=3, random_state=42,
    )
    reg.fit(X, y_reg)
    reg_models[ta] = reg
    print(f"  {ta}: clf trained on {len(subset):,} rows  "
          f"(stall rate: {y_clf.mean():.1%})")

# Global fallback using all TAs
X_all  = train_df[FEATURES].fillna(0).values
clf_global = GradientBoostingClassifier(
    n_estimators=120, max_depth=4, learning_rate=0.08,
    subsample=0.8, min_samples_leaf=3, random_state=42,
)
clf_global.fit(X_all, train_df["next_month_is_stall"].values)
reg_global = GradientBoostingRegressor(
    n_estimators=100, max_depth=3, learning_rate=0.08,
    subsample=0.8, min_samples_leaf=3, random_state=42,
)
reg_global.fit(X_all, train_df["rands_this_month"].values.astype(float))
print(f"  Global fallback: trained on {len(train_df):,} rows")

# COMMAND ----------
# ── Inference: latest-month snapshot for each site-study pair ─────────────────

latest_df = (
    feat_all.sort_values("month_index")
    .groupby(["study_id", "site_id"])
    .last()
    .reset_index()
)
print(f"Inference rows (one per site-study pair): {len(latest_df):,}")

stall_probs     = []
next_rands_preds = []

for _, row in latest_df.iterrows():
    ta  = row["ta"]
    clf = clf_models.get(ta, clf_global)
    reg = reg_models.get(ta, reg_global)
    x   = row[FEATURES].fillna(0).values.reshape(1, -1)
    stall_p     = float(clf.predict_proba(x)[0, 1])
    reg_pred    = float(max(0.0, reg.predict(x)[0]))

    # Blend regression with stall-adjusted trailing average.
    # The regressor is trained on rands_this_month which includes ~20% stall
    # (zero) months; on short (12-month) training windows it can underpredict.
    # The floor ensures predictions never collapse below the site's recent
    # enrollment rate discounted by its predicted stall probability.
    trailing_avg = float(row.get("trailing_3m_avg_rands", 0.0) or 0.0)
    floor        = trailing_avg * max(0.0, 1.0 - stall_p)
    next_rands   = max(reg_pred, floor)

    stall_probs.append(stall_p)
    next_rands_preds.append(next_rands)

latest_df["predicted_stall_prob"]          = stall_probs
latest_df["predicted_next_month_rands"]    = next_rands_preds

print(f"Stall prob — mean: {np.mean(stall_probs):.3f}  "
      f"p25: {np.percentile(stall_probs, 25):.3f}  "
      f"p75: {np.percentile(stall_probs, 75):.3f}")
print(f"Next-month rands — mean: {np.mean(next_rands_preds):.3f}  "
      f"p25: {np.percentile(next_rands_preds, 25):.3f}  "
      f"p75: {np.percentile(next_rands_preds, 75):.3f}")

# COMMAND ----------
# ── SHAP attributions ──────────────────────────────────────────────────────────

shap_rows = []

for ta in TAS:
    clf = clf_models.get(ta, clf_global)
    ta_df = latest_df[latest_df["ta"] == ta].copy()
    if len(ta_df) == 0:
        continue

    X_ta = ta_df[FEATURES].fillna(0).values
    explainer   = shap.TreeExplainer(clf)
    shap_values = explainer.shap_values(X_ta)

    # GBC returns list [class0, class1] or 2D array depending on version
    if isinstance(shap_values, list):
        sv = np.array(shap_values[1])   # class=1 (stall)
    else:
        sv = np.array(shap_values)
    if sv.ndim == 3:
        sv = sv[:, :, 1]

    for i, (_, site_row) in enumerate(ta_df.iterrows()):
        site_shap = sv[i]
        # Top 5 by absolute value
        ranked = sorted(
            zip(FEATURES, site_shap),
            key=lambda kv: abs(kv[1]), reverse=True
        )[:5]
        for rank, (feat_name, shap_val) in enumerate(ranked, start=1):
            shap_rows.append({
                "site_id":              site_row["site_id"],
                "study_id":             site_row["study_id"],
                "feature_name":         feat_name,
                "feature_display_name": FEATURE_DISPLAY.get(feat_name, feat_name),
                "shap_value":           round(float(shap_val), 5),
                "abs_shap_value":       round(abs(float(shap_val)), 5),
                "direction":            "negative" if shap_val > 0 else "positive",
                "feature_value":        str(round(float(site_row[feat_name]), 4)),
                "rank":                 rank,
            })

shap_out_df = pd.DataFrame(shap_rows)
print(f"SHAP rows: {len(shap_out_df):,}")

# COMMAND ----------
# ── Write gold_model_predictions ──────────────────────────────────────────────

from pyspark.sql.types import StructType, StructField, StringType, DoubleType, IntegerType

pred_out = latest_df[["study_id", "site_id",
                       "predicted_stall_prob",
                       "predicted_next_month_rands"]].copy()
pred_out["is_latest"] = 1
pred_out["predicted_stall_prob"]       = pred_out["predicted_stall_prob"].round(5)
pred_out["predicted_next_month_rands"] = pred_out["predicted_next_month_rands"].round(3)

# Reorder columns to match pred_schema field order.
# spark.createDataFrame maps pandas columns by POSITION, not by name —
# if the order doesn't match the StructType the site_id/study_id columns
# get swapped and the JOIN in the backend returns NULL for every row.
pred_out = pred_out[["site_id", "study_id",
                      "predicted_next_month_rands",
                      "predicted_stall_prob",
                      "is_latest"]]

pred_schema = StructType([
    StructField("site_id",                    StringType(),  False),
    StructField("study_id",                   StringType(),  False),
    StructField("predicted_next_month_rands", DoubleType(),  True),
    StructField("predicted_stall_prob",       DoubleType(),  True),
    StructField("is_latest",                  IntegerType(), True),
])
spark.createDataFrame(pred_out, pred_schema) \
    .write.format("delta").mode("overwrite") \
    .saveAsTable(f"{CATALOG}.ml_features.gold_model_predictions")
print(f"gold_model_predictions: {len(pred_out):,} rows written")

# COMMAND ----------
# ── Write gold_shap_values ────────────────────────────────────────────────────

shap_schema = StructType([
    StructField("site_id",              StringType(), False),
    StructField("study_id",             StringType(), False),
    StructField("feature_name",         StringType(), True),
    StructField("feature_display_name", StringType(), True),
    StructField("shap_value",           DoubleType(), True),
    StructField("abs_shap_value",       DoubleType(), True),
    StructField("direction",            StringType(), True),
    StructField("feature_value",        StringType(), True),
    StructField("rank",                 IntegerType(), True),
])
spark.createDataFrame(shap_out_df, shap_schema) \
    .write.format("delta").mode("overwrite") \
    .saveAsTable(f"{CATALOG}.ml_features.gold_shap_values")
print(f"gold_shap_values: {len(shap_out_df):,} rows written")

# COMMAND ----------
# ── Refresh gold_site_feasibility_scores ──────────────────────────────────────
# Update operational_performance_score and composite using real predicted_stall_prob.
# RWE, selection, and protocol scores remain as computed by 00_seed_data.py.

scores_df = spark.table(f"{CATALOG}.ml_features.gold_site_feasibility_scores").toPandas()

# Merge in real stall prob
scores_df = scores_df.merge(
    pred_out[["study_id", "site_id", "predicted_stall_prob"]],
    on=["study_id", "site_id"], how="left"
)
# Merge in trailing velocity for the velocity component of op_score
scores_df = scores_df.merge(
    latest_df[["study_id", "site_id", "trailing_3m_avg_rands", "ta"]],
    on=["study_id", "site_id"], how="left"
)

# TA benchmark: median trailing_3m_avg_rands per TA (from latest snapshot)
ta_benchmarks = latest_df.groupby("ta")["trailing_3m_avg_rands"].median().to_dict()

def _op_score(row):
    stall_p  = row.get("predicted_stall_prob")
    if stall_p is None or pd.isna(stall_p):
        stall_p = 0.5
    t3       = row.get("trailing_3m_avg_rands", 0.0) or 0.0
    ta       = row.get("ta", "CNS")
    bench    = ta_benchmarks.get(ta, 1.0) or 1.0
    vel_ratio = min(t3 / bench, 2.0)     # cap at 2× benchmark
    op = (0.6 * (1.0 - stall_p) + 0.4 * min(vel_ratio / 2.0, 1.0)) * 100.0
    return round(min(100.0, max(0.0, op)), 1)

scores_df["operational_performance_score"] = scores_df.apply(_op_score, axis=1)
scores_df["composite_feasibility_score"] = (
    0.35 * scores_df["rwe_patient_access_score"]
    + 0.30 * scores_df["operational_performance_score"]
    + 0.20 * scores_df["site_selection_score"]
    + 0.15 * scores_df["protocol_execution_score"]
).round(2)

# Drop helper columns before writing back
scores_out = scores_df.drop(columns=["predicted_stall_prob", "trailing_3m_avg_rands", "ta"],
                             errors="ignore")

fs_schema = StructType([
    StructField("site_id",                       StringType(), False),
    StructField("study_id",                      StringType(), False),
    StructField("model_ta_segment",              StringType(), True),
    StructField("country",                       StringType(), True),
    StructField("rwe_patient_access_score",      DoubleType(), True),
    StructField("rwe_patient_count_state",       IntegerType(), True),
    StructField("operational_performance_score", DoubleType(), True),
    StructField("site_selection_score",          DoubleType(), True),
    StructField("site_selection_probability",    DoubleType(), True),
    StructField("ssq_status",                    StringType(), True),
    StructField("protocol_execution_score",      DoubleType(), True),
    StructField("composite_feasibility_score",   DoubleType(), True),
])
spark.createDataFrame(scores_out, fs_schema) \
    .write.format("delta").mode("overwrite") \
    .saveAsTable(f"{CATALOG}.ml_features.gold_site_feasibility_scores")
print(f"gold_site_feasibility_scores: {len(scores_out):,} rows refreshed")
print(f"  Composite — mean: {scores_out['composite_feasibility_score'].mean():.1f}  "
      f"p25: {scores_out['composite_feasibility_score'].quantile(0.25):.1f}  "
      f"p75: {scores_out['composite_feasibility_score'].quantile(0.75):.1f}")

# COMMAND ----------
# ── Refresh gold_feasibility_dimension_drivers (op dimension) ─────────────────
# Re-write the op dimension rows with real stall_prob and velocity values.
# rwe / sel / proto rows remain unchanged.

drivers_df = spark.table(f"{CATALOG}.ml_features.gold_feasibility_dimension_drivers").toPandas()

# Merge helper columns into scores_df (already has op_score and stall_prob)
op_lookup = scores_df[["study_id", "site_id", "operational_performance_score",
                        "predicted_stall_prob", "trailing_3m_avg_rands", "ta"]].copy()
op_lookup = op_lookup.merge(
    pred_out[["study_id", "site_id", "predicted_stall_prob"]],
    on=["study_id", "site_id"], how="left",
    suffixes=("", "_pred")
)

# Drop existing op rows
drivers_non_op = drivers_df[drivers_df["dimension"] != "op"].copy()

# Rebuild op rows
op_rows = []
ta_benchmarks_full = latest_df.groupby("ta")["trailing_3m_avg_rands"].median().to_dict()

for _, r in op_lookup.iterrows():
    study_id   = r["study_id"]
    site_id    = r["site_id"]
    stall_p    = float(r.get("predicted_stall_prob_pred") or r.get("predicted_stall_prob") or 0.5)
    t3         = float(r.get("trailing_3m_avg_rands") or 0.0)
    ta         = str(r.get("ta") or "CNS")
    bench      = ta_benchmarks_full.get(ta, 1.0) or 1.0
    vel_ratio  = min(t3 / bench, 2.0)
    op_score   = float(r["operational_performance_score"])

    # months active = last month_index for this pair where screens > 0
    ma_row = enroll_df[
        (enroll_df["study_id"] == study_id) &
        (enroll_df["site_id"]  == site_id)  &
        (enroll_df["screens_this_month"] > 0)
    ]
    months_active = int(ma_row["month_index"].max()) if len(ma_row) else 1

    drivers = [
        # rank, feature_name, display, raw_val, display_val, contrib_frac, inverted
        (1, "stall_prob",       "Predicted Stall Probability",
         stall_p,  f"{round(stall_p*100,1)}%",       0.60, True),
        (2, "velocity_ratio",   "Enrollment Velocity vs Benchmark",
         vel_ratio, f"{round(vel_ratio,2)}×",         0.40, False),
        (3, "months_active",    "Months Since Activation",
         float(months_active), f"{months_active} months", 0.20, False),
    ]
    for rank, feat_name, feat_display, raw_val, disp_val, contrib_frac, inverted in drivers:
        contrib = round(op_score * contrib_frac, 2)
        contrib_pct = round(contrib / max(op_score, 1.0), 4)
        direction = ("negative" if inverted else "positive") if raw_val > 0 else (
                     "positive" if inverted else "negative")
        op_rows.append({
            "study_id":              study_id,
            "site_id":               site_id,
            "dimension":             "op",
            "rank":                  rank,
            "feature_name":          feat_name,
            "feature_display_name":  feat_display,
            "feature_value_raw":     round(raw_val, 5),
            "feature_value_display": disp_val,
            "contribution":          contrib,
            "contribution_pct":      contrib_pct,
            "direction":             direction,
            "dimension_score":       round(op_score, 1),
        })

op_df  = pd.DataFrame(op_rows)
full_drivers_df = pd.concat([drivers_non_op, op_df], ignore_index=True)

driver_schema = StructType([
    StructField("study_id",              StringType(), False),
    StructField("site_id",               StringType(), False),
    StructField("dimension",             StringType(), True),
    StructField("rank",                  IntegerType(), True),
    StructField("feature_name",          StringType(), True),
    StructField("feature_display_name",  StringType(), True),
    StructField("feature_value_raw",     DoubleType(), True),
    StructField("feature_value_display", StringType(), True),
    StructField("contribution",          DoubleType(), True),
    StructField("contribution_pct",      DoubleType(), True),
    StructField("direction",             StringType(), True),
    StructField("dimension_score",       DoubleType(), True),
])
spark.createDataFrame(full_drivers_df, driver_schema) \
    .write.format("delta").mode("overwrite") \
    .saveAsTable(f"{CATALOG}.ml_features.gold_feasibility_dimension_drivers")
print(f"gold_feasibility_dimension_drivers: {len(full_drivers_df):,} rows written")

